import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"音之呼吸","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/音之呼吸.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/音之呼吸.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/音之呼吸.md"};function d(b,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"音之呼吸",tabindex:"-1"},[n("音之呼吸 "),r("a",{class:"header-anchor",href:"#音之呼吸","aria-label":'Permalink to "音之呼吸"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="音之呼吸-1" tabindex="-1">音之呼吸 <a class="header-anchor" href="#音之呼吸-1" aria-label="Permalink to &quot;音之呼吸&quot;">​</a></h1><p>音之呼吸<br> 前置：呼吸法<br> 下属技艺使用条件：剑/刀类近战武器</p><p>【呼吸】<br> 拥有该词条的单位在进行一次以生理属性作为关键属性的攻击前须投掷一个D10的自然骰，若出目不大于呼吸层数，则令这次攻击造成的伤害增加一半并消耗一层呼吸层数。<br> 一个单位的具有呼吸层数上限为10层。<br> 呼吸层数会在战斗结束时清空。</p><p>音之呼吸一之型·轰：<br> D+500<br> 通过斩击引起爆炸，造成伴随着轰鸣的斩击。<br> 以一个标准动作消耗2点呼吸法进行一次白刃攻击，本次攻击结束后获得1层【呼吸】，若当前的【呼吸】层数大于5，该次攻击还将攻击你触及范围内的所有单位。</p><p>音之呼吸四之型·响斩无间：<br> C+1000<br> 利用斩击和爆炸在自己面前制造一个巨大的空间，进行广泛地攻击，这个招式可以迅速应对对手发动的大范围攻击。<br> 以一个标准动作消耗4点呼吸法进行一次全防御，然后获得2层【呼吸】，且直到下一轮开始，使用者具有【封闭3】。</p><p>音之呼吸五之型·鸣弦叠奏：<br> B+2000<br> 用分别高速回旋的刀刃带出爆炸，冲向对方发动猛攻。每一次旋转都伴随着爆炸，冲击着周边。<br> 以一个标准动作消耗8点呼吸法进行两次白刃攻击，这两次攻击都具有【碾压】特性，若在此次攻击的当轮或上一轮使用了至少1个其他音之呼吸招式，本次攻击结束后获得3层【呼吸】</p><p>忍者的技术<br> D+750<br> 音之呼吸的所有招数皆需要在斩击的同时抛出一定量的炸药进行爆炸攻击，因此不同于常规的呼吸法招数，爆炸的部分需要额外进行训练。</p><p>当你使用音之呼吸的招数进行攻击时，可以额外进行一次智力+学识+专业：炸药学+专业：数学（学识）的检定，该次攻击将额外具有不超过华丽计数的检定成功数的音波伤害。</p><p>华丽计数：初始为0，在具有忍者的技术后每经过一场影片，计数+1，最高上限12点。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
